/**
 * validation.js
 * Reusable input-validation helpers for Express route handlers.
 *
 * Each validator returns an array of human-readable error strings.
 * An empty array means "all checks passed".
 *
 * Usage:
 *   const { validateUserId, validateUserBody, validationMiddleware } = require('./validation');
 */

'use strict';

// ---------------------------------------------------------------------------
// Low-level field validators
// ---------------------------------------------------------------------------

/**
 * Returns true when `value` is a finite integer (or a string that parses to one).
 */
function isNumericId(value) {
  if (value === undefined || value === null) return false;
  const num = Number(value);
  return Number.isFinite(num) && Number.isInteger(num) && num > 0;
}

/**
 * Returns true when `value` is a non-null primitive string.
 */
function isString(value) {
  return typeof value === 'string';
}

/**
 * Very permissive but RFC-5321-compliant length-capped e-mail check.
 * Requires: local@domain.tld — no consecutive dots, no leading/trailing dots
 * in the local part, domain must have at least one dot.
 */
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
function isValidEmail(value) {
  if (!isString(value)) return false;
  return EMAIL_RE.test(value) && value.length <= 254;
}

// ---------------------------------------------------------------------------
// Field-level error collectors
// ---------------------------------------------------------------------------

/**
 * Validate a route parameter that must be a positive integer id.
 * @param {*}      value     - The raw value (e.g. req.params.id)
 * @param {string} fieldName - Label used in error messages
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateId(value, fieldName = 'id') {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`"${fieldName}" is required`);
  } else if (!isNumericId(value)) {
    errors.push(`"${fieldName}" must be a positive integer, received: ${JSON.stringify(value)}`);
  }
  return errors;
}

/**
 * Validate a "name" field.
 * Rules: required, must be a string, length 1-100 characters.
 * @param {*}      value     - The raw value
 * @param {string} fieldName - Label used in error messages
 * @param {object} [opts]
 * @param {boolean} [opts.required=true]   - Whether absence is an error
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateName(value, fieldName = 'name', { required = true } = {}) {
  const errors = [];
  const absent = value === undefined || value === null;

  if (absent) {
    if (required) errors.push(`"${fieldName}" is required`);
    return errors; // nothing more to check when value is absent
  }

  if (!isString(value)) {
    errors.push(`"${fieldName}" must be a string, received: ${typeof value}`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push(`"${fieldName}" must not be blank (minimum 1 character)`);
  } else if (trimmed.length > 100) {
    errors.push(
      `"${fieldName}" is too long (${trimmed.length} characters); maximum is 100 characters`,
    );
  }

  return errors;
}

/**
 * Validate an "email" field.
 * Rules: required, must be a string, valid e-mail format, max 254 characters.
 * @param {*}      value     - The raw value
 * @param {string} fieldName - Label used in error messages
 * @param {object} [opts]
 * @param {boolean} [opts.required=true] - Whether absence is an error
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateEmail(value, fieldName = 'email', { required = true } = {}) {
  const errors = [];
  const absent = value === undefined || value === null;

  if (absent) {
    if (required) errors.push(`"${fieldName}" is required`);
    return errors;
  }

  if (!isString(value)) {
    errors.push(`"${fieldName}" must be a string, received: ${typeof value}`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(
      `"${fieldName}" is too long (${value.length} characters); maximum is 254 characters`,
    );
  } else if (!EMAIL_RE.test(value)) {
    errors.push(
      `"${fieldName}" must be a valid e-mail address (e.g. user@example.com), received: ${JSON.stringify(value)}`,
    );
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators (combine field validators for specific endpoints)
// ---------------------------------------------------------------------------

/**
 * Validate a numeric route-param id (e.g. /users/:id).
 * @param {object} params - req.params
 * @returns {string[]}
 */
function validateUserId(params) {
  return validateId(params && params.id, 'id');
}

/**
 * Validate the request body for POST /users (all fields required).
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateCreateUserBody(body) {
  const b = body || {};
  return [
    ...validateName(b.name, 'name', { required: true }),
    ...validateEmail(b.email, 'email', { required: true }),
  ];
}

/**
 * Validate the request body for PUT /users/:id (fields optional, but
 * validated when present so you cannot submit a bad value).
 * At least one updatable field must be provided.
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateUpdateUserBody(body) {
  const b = body || {};
  const errors = [];

  const nameProvided = b.name !== undefined && b.name !== null;
  const emailProvided = b.email !== undefined && b.email !== null;

  if (!nameProvided && !emailProvided) {
    errors.push('At least one field must be provided for update: "name", "email"');
    return errors;
  }

  if (nameProvided) {
    errors.push(...validateName(b.name, 'name', { required: false }));
  }
  if (emailProvided) {
    errors.push(...validateEmail(b.email, 'email', { required: false }));
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Build an Express middleware that runs one or more validator functions,
 * collects all errors, and either passes control to next() or responds
 * with a descriptive 400 JSON payload.
 *
 * Validator functions receive (req) and must return string[].
 *
 * @param {...function} validators - Functions of the form (req) => string[]
 * @returns {function} Express middleware (req, res, next) => void
 *
 * @example
 *   router.post('/users',
 *     validationMiddleware(
 *       req => validateCreateUserBody(req.body),
 *     ),
 *     createUserHandler,
 *   );
 */
function validationMiddleware(...validators) {
  return function (req, res, next) {
    const errors = validators.flatMap((fn) => fn(req));

    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }

    return next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Low-level helpers (useful for unit tests or custom validators)
  isNumericId,
  isString,
  isValidEmail,

  // Field-level validators
  validateId,
  validateName,
  validateEmail,

  // Composite validators
  validateUserId,
  validateCreateUserBody,
  validateUpdateUserBody,

  // Middleware factory
  validationMiddleware,
};

