 * validation.js – reusable input-validation helpers.
 *
 * Each validator returns an array of error strings (empty = valid).
 * validateUser() and validateUserId() are the two main entry points
 * consumed by the route handlers in app.js.
 */

'use strict';

// RFC-5321 / RFC-5322 inspired pattern that covers the vast majority of
// real-world addresses without being overly permissive.
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// ---------------------------------------------------------------------------
// Field-level validators
// ---------------------------------------------------------------------------

/**
 * Validate an "id" value (route param or body field).
 * Accepts a numeric string (e.g. "42") or an actual number.
 * Returns an array of error strings.
 */
function validateId(id, fieldName = 'id') {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push(`"${fieldName}" is required`);
    return errors;            // no point checking further
  }

  const asNumber = Number(id);
  if (!Number.isFinite(asNumber) || asNumber !== Math.floor(asNumber)) {
    errors.push(`"${fieldName}" must be a numeric integer (received: ${JSON.stringify(id)})`);
  } else if (asNumber <= 0) {
    errors.push(`"${fieldName}" must be a positive integer (received: ${asNumber})`);
  }

  return errors;
}

/**
 * Validate a "name" field.
 * Must be a non-empty string between 1 and 100 characters.
 * Returns an array of error strings.
 */
function validateName(name, required = true) {
  const errors = [];

  if (name === undefined || name === null) {
    if (required) errors.push('"name" is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push(`"name" must be a string (received: ${typeof name})`);
    return errors;
  }

  const trimmed = name.trim();
  if (trimmed.length === 0) {
    errors.push('"name" must not be blank');
  } else if (trimmed.length > 100) {
    errors.push(`"name" must be 100 characters or fewer (received: ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an "email" field.
 * Must be a string matching a basic email pattern, max 254 chars.
 * Returns an array of error strings.
 */
function validateEmail(email, required = true) {
  const errors = [];

  if (email === undefined || email === null) {
    if (required) errors.push('"email" is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push(`"email" must be a string (received: ${typeof email})`);
    return errors;
  }

  if (email.length > 254) {
    errors.push(`"email" must be 254 characters or fewer (received: ${email.length})`);
  }

  if (!EMAIL_RE.test(email)) {
    errors.push(`"email" must be a valid email address (received: ${JSON.stringify(email)})`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators (used by route handlers)
// ---------------------------------------------------------------------------

/**
 * Validate the :id route parameter.
 * @param {string|number} id
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUserId(id) {
  const errors = validateId(id, 'id');
  return { valid: errors.length === 0, errors };
}

/**
 * Validate a user payload (POST body or PUT body).
 *
 * @param {object}  body           - parsed request body
 * @param {object}  [opts]
 * @param {boolean} [opts.requireAll=true] - when false, only present fields
 *                                           are validated (useful for PATCH/PUT)
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUserBody(body, { requireAll = true } = {}) {
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return { valid: false, errors: ['Request body must be a JSON object'] };
  }

  const errors = [
    ...validateName(body.name, requireAll || body.name !== undefined),
    ...validateEmail(body.email, requireAll || body.email !== undefined),
  ];

  return { valid: errors.length === 0, errors };
}

module.exports = { validateUserId, validateUserBody };

