/**
 * validation.js – reusable input-validation helpers for API route handlers.
 *
 * Each validator returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Returns an error message if `value` is absent (undefined, null, or the
 * empty string after trimming).
 */
function validateRequired(fieldName, value) {
  if (value === undefined || value === null || String(value).trim() === '') {
    return `"${fieldName}" is required`;
  }
  return null;
}

/**
 * Returns an error message if `value` is not a finite integer (or a string
 * that parses to one).  Floats, NaN, Infinity, and numeric strings with
 * decimal points are all rejected.
 */
function validateNumericId(fieldName, value) {
  if (value === undefined || value === null) return null; // let validateRequired handle absence
  const asNumber = Number(value);
  if (!Number.isInteger(asNumber) || asNumber <= 0) {
    return `"${fieldName}" must be a positive integer`;
  }
  return null;
}

/**
 * Returns an error message if `value` is not a string (or is not string-like
 * when the surrounding JSON has already coerced it).
 */
function validateString(fieldName, value) {
  if (value === undefined || value === null) return null; // let validateRequired handle absence
  if (typeof value !== 'string') {
    return `"${fieldName}" must be a string`;
  }
  return null;
}

/**
 * Returns an error message if the string `value` falls outside [min, max].
 */
function validateStringLength(fieldName, value, min, max) {
  if (typeof value !== 'string') return null; // let validateString handle type
  const len = value.trim().length;
  if (len < min || len > max) {
    return `"${fieldName}" must be between ${min} and ${max} characters`;
  }
  return null;
}

/**
 * Returns an error message if `value` does not look like a valid e-mail
 * address.  Uses the RFC 5321-informed regex that most validators rely on;
 * intentionally not exhaustive but correct for common cases.
 */
function validateEmail(fieldName, value) {
  if (typeof value !== 'string') return null; // let validateString handle type
  // Local part: printable ASCII excluding spaces and @
  // Domain part: at least one dot-separated label
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(value.trim())) {
    return `"${fieldName}" must be a valid email address`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Composed validators for common field groups
// ---------------------------------------------------------------------------

/**
 * Validate a user `id` coming from a URL parameter.
 * Returns an array of error strings (empty = valid).
 */
function validateUserId(id) {
  const errors = [];
  const required = validateRequired('id', id);
  if (required) { errors.push(required); return errors; }
  const numeric = validateNumericId('id', id);
  if (numeric) errors.push(numeric);
  return errors;
}

/**
 * Validate the body fields for creating a new user (POST /users).
 * Both `name` and `email` are required.
 * Returns an array of error strings (empty = valid).
 */
function validateCreateUserBody(body) {
  const errors = [];
  const { name, email } = body || {};

  // --- name ---
  const nameRequired = validateRequired('name', name);
  if (nameRequired) {
    errors.push(nameRequired);
  } else {
    const nameType = validateString('name', name);
    if (nameType) errors.push(nameType);
    const nameLength = validateStringLength('name', name, 1, 100);
    if (nameLength) errors.push(nameLength);
  }

  // --- email ---
  const emailRequired = validateRequired('email', email);
  if (emailRequired) {
    errors.push(emailRequired);
  } else {
    const emailType = validateString('email', email);
    if (emailType) errors.push(emailType);
