 *
 * Each exported function returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const NAME_MIN = 1;
const NAME_MAX = 100;
const EMAIL_MAX = 254;

/**
 * Validate a route parameter that must be a positive integer (e.g. :id).
 *
 * @param {string} raw   - The raw string value from req.params.
 * @param {string} field - The field name used in error messages.
 * @returns {string[]}   - Array of validation error messages.
 */
function validateIdParam(raw, field = 'id') {
  const errors = [];

  if (raw === undefined || raw === null || raw === '') {
    errors.push(`"${field}" is required`);
    return errors;
  }

  const num = Number(raw);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a "name" field.
 *
 * @param {*}      value    - The value to validate.
 * @param {string} field    - The field name used in error messages.
 * @param {boolean} required - Whether the field is mandatory.
 * @returns {string[]}
 */
function validateName(value, field = 'name', required = true) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';
  if (missing) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < NAME_MIN) {
    errors.push(`"${field}" must be at least ${NAME_MIN} character(s) long`);
  }
  if (trimmed.length > NAME_MAX) {
    errors.push(`"${field}" must be at most ${NAME_MAX} characters long`);
  }

  return errors;
}

/**
 * Validate an "email" field.
 *
 * @param {*}      value    - The value to validate.
 * @param {string} field    - The field name used in error messages.
 * @param {boolean} required - Whether the field is mandatory.
 * @returns {string[]}
 */
function validateEmail(value, field = 'email', required = true) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';
  if (missing) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (value.length > EMAIL_MAX) {
    errors.push(`"${field}" must be at most ${EMAIL_MAX} characters long`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  return errors;
}

/**
 * Validate the body for creating a user (POST /users).
 * Both "name" and "email" are required.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name, 'name', true),
    ...validateEmail(body.email, 'email', true),
  ];
}

/**
 * Validate the body for updating a user (PUT /users/:id).
 * At least one of "name" or "email" must be provided; whichever is provided
 * must still pass its type / length / format rules.
 *
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateUpdateUser(body) {
  const errors = [];

  const hasName  = body.name  !== undefined && body.name  !== null && body.name  !== '';
  const hasEmail = body.email !== undefined && body.email !== null && body.email !== '';

  if (!hasName && !hasEmail) {
    errors.push('At least one of "name" or "email" must be provided');
    return errors;
  }

  if (hasName)  errors.push(...validateName(body.name,   'name',  false));
  if (hasEmail) errors.push(...validateEmail(body.email, 'email', false));

  return errors;
}

/**
 * Express middleware factory.
 * Pass a validator function; the middleware calls it and, if errors exist,
 * responds with 400 and a structured error body.
 *
 * Usage:
 *   app.post('/users', validate(validateCreateUser), handler);
 *
 * @param {Function} validatorFn - A function(body | param) => string[]
 * @param {'body'|'params'} source - Where to pull the data from (default: 'body')
 * @returns {Function} Express middleware
 */
function validate(validatorFn, source = 'body') {
  return (req, res, next) => {
    const data = source === 'params' ? req.params : req.body;
    const errors = validatorFn(data);

    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }

    next();
  };
}

module.exports = {
  validateIdParam,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validate,
};

