// validation.js — reusable input validation helpers

/**
 * Email regex per RFC 5321 practical limits.
 * Accepts standard addresses like user@example.com,
 * user+tag@sub.domain.org, etc.
 */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a numeric route/query parameter (e.g. :id).
 * Accepts strings that represent whole positive integers.
 *
 * @param {string} value   - raw value from req.params or req.query
 * @param {string} field   - field name to use in error messages
 * @param {string[]} errors - accumulator array; errors are pushed here
 * @returns {number|undefined} parsed integer, or undefined on failure
 */
function validateId(value, field, errors) {
  if (value === undefined || value === null || value === '') {
    errors.push(`${field} is required`);
    return undefined;
  }
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`${field} must be a positive integer`);
    return undefined;
  }
  return num;
}

/**
 * Validate a required string field.
 *
 * @param {*}        value   - value from req.body
 * @param {string}   field   - field name for error messages
 * @param {object}   opts    - { minLength, maxLength }
 * @param {string[]} errors  - accumulator array
 * @returns {string|undefined} trimmed string, or undefined on failure
 */
function validateString(value, field, opts, errors) {
  const { minLength = 1, maxLength } = opts;

  if (value === undefined || value === null) {
    errors.push(`${field} is required`);
    return undefined;
  }
  if (typeof value !== 'string') {
    errors.push(`${field} must be a string`);
    return undefined;
  }

  const trimmed = value.trim();

  if (trimmed.length < minLength) {
    errors.push(
      `${field} must be at least ${minLength} character${minLength !== 1 ? 's' : ''}`
    );
    return undefined;
  }
  if (maxLength !== undefined && trimmed.length > maxLength) {
    errors.push(`${field} must be at most ${maxLength} characters`);
    return undefined;
  }

  return trimmed;
}

/**
 * Validate an email field (presence, type, format, length).
 *
 * @param {*}        value  - value from req.body
 * @param {string}   field  - field name for error messages
 * @param {string[]} errors - accumulator array
 * @returns {string|undefined} lowercased email, or undefined on failure
 */
function validateEmail(value, field, errors) {
  if (value === undefined || value === null) {
    errors.push(`${field} is required`);
    return undefined;
  }
  if (typeof value !== 'string') {
    errors.push(`${field} must be a string`);
    return undefined;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push(`${field} is required`);
    return undefined;
  }
  if (trimmed.length > 254) {
    errors.push(`${field} must be at most 254 characters`);
    return undefined;
  }
  if (!EMAIL_REGEX.test(trimmed)) {
    errors.push(`${field} must be a valid email address`);
    return undefined;
  }

  return trimmed.toLowerCase();
}

/**
 * Validate the fields common to creating or updating a user:
 * name (string, 1–100 chars) and email (valid address, max 254 chars).
 *
 * @param {object}   body   - req.body
 * @param {string[]} errors - accumulator array
 * @returns {{ name: string|undefined, email: string|undefined }}
 */
function validateUserBody(body, errors) {
  const name = validateString(body.name, 'name', { minLength: 1, maxLength: 100 }, errors);
  const email = validateEmail(body.email, 'email', errors);
  return { name, email };
}

/**
 * Express middleware factory: validates :id in route params.
 * Attaches the parsed integer to req.validatedId on success,
 * or responds with 400 immediately on failure.
 */
function requireNumericId(req, res, next) {
  const errors = [];
  const id = validateId(req.params.id, 'id', errors);
  if (errors.length > 0) {
    return res.status(400).json({ errors });
  }
  req.validatedId = id;
  next();
}

module.exports = {
  validateId,
  validateString,
  validateEmail,
  validateUserBody,
  requireNumericId,
};

