 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate the body payload for updating a user (all fields required).
 *
 * @param {{ name: *, email: * }} body
 * @returns {string[]} combined array of error messages
 */
function validateUpdateUser(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Express middleware factory — sends a 400 response if the provided errors
 * array is non-empty, otherwise calls next().
 *
 * @param {string[]} errors
 * @param {import('express').Response} res
 * @param {import('express').NextFunction} next
 */
function rejectIfInvalid(errors, res, next) {
  if (errors.length > 0) {
    return res.status(400).json({ errors });
  }
  next();
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  rejectIfInvalid,
};
